const TIME_ZONE = 'America/Los_Angeles';
const SUBJECT = 'Remember to Email/Call this lead';
const WORKFLOW_NAME = 'W15 - Requested Follow Up Weekly Task';
const WORKFLOW_MARKER = `Workflow: ${WORKFLOW_NAME}`;

function currentMondayInTimeZone(date, timeZone) {
  const parts = new Intl.DateTimeFormat('en-US', {
    timeZone,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    weekday: 'short',
  }).formatToParts(date);
  const values = Object.fromEntries(parts.map((part) => [part.type, part.value]));
  const weekdayNumber = {
    Mon: 1,
    Tue: 2,
    Wed: 3,
    Thu: 4,
    Fri: 5,
    Sat: 6,
    Sun: 7,
  }[values.weekday];
  const mondayUtc = new Date(Date.UTC(
    Number(values.year),
    Number(values.month) - 1,
    Number(values.day) - (weekdayNumber - 1),
  ));
  return mondayUtc.toISOString().slice(0, 10);
}

const mondayDate = currentMondayInTimeZone(new Date(), TIME_ZONE);
const tasksByLead = new Map();

for (const item of $('Fetch Weekly Reminder Tasks').all()) {
  const task = item.json || {};
  const leadId = String(task.WhoId || '');
  const description = String(task.Description || '');
  if (!leadId || task.Subject !== SUBJECT || !description.includes(WORKFLOW_MARKER)) continue;
  if (!tasksByLead.has(leadId)) tasksByLead.set(leadId, []);
  tasksByLead.get(leadId).push(task);
}

const results = [];
for (const item of $('Fetch Requested Follow Up Leads').all()) {
  const lead = item.json || {};
  const leadId = String(lead.Id || '');
  if (!leadId) continue;

  const leadTasks = tasksByLead.get(leadId) || [];
  const hasCompletedTask = leadTasks.some((task) => String(task.Status || '') === 'Completed');
  const hasCurrentMondayTask = leadTasks.some(
    (task) => String(task.ActivityDate || '').slice(0, 10) === mondayDate,
  );
  const leadOwnerId = String(lead.OwnerId || '').trim();

  let decision = 'create';
  if (!leadOwnerId) decision = 'missingOwner';
  else if (hasCompletedTask) decision = 'completed';
  else if (hasCurrentMondayTask) decision = 'currentMonday';

  results.push({
    json: {
      leadId,
      leadName: String(lead.Name || ''),
      leadOwnerId,
      engagementStatus: String(lead.Engagement_Status__c || ''),
      mondayDate,
      hasCompletedTask,
      hasCurrentMondayTask,
      decision,
      taskSubject: SUBJECT,
      taskDescription: `Weekly reminder to email or call this lead.\n\nLead: ${String(lead.Name || '')}\nEngagement Status: Requested Follow Up\nWorkflow: ${WORKFLOW_NAME}`,
    },
  });
}

return results;
